import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
@Service
@Transactional
public class TransferService {
    private final AccountRepository repo;
    TransferService(AccountRepository repo) { this.repo=repo; }

    public void transfer(String fromId, String toId, double amount) {
        Account from = repo.findById(fromId).orElseThrow(() -> new IllegalArgumentException("Not found: " + fromId));
        Account to   = repo.findById(toId).orElseThrow(() -> new IllegalArgumentException("Not found: " + toId));
        from.debit(amount);
        to.credit(amount);
        repo.save(from);
        repo.save(to);
    }
}

