@Service @Transactional
public class ProductService {
    private final ProductRepository repo;
    ProductService(ProductRepository r) { repo=r; }
    public Product create(String n, double p, String c) {
        if (repo.existsByName(n)) throw new IllegalStateException("Exists: "+n);
        return repo.save(new Product(n,p,c));
    }
    public Optional<Product> findById(String id) { return repo.findById(id); }
    public List<Product> findAll() { return repo.findAll(); }
    public Product update(String id, String n, double p) {
        Product pr = repo.findById(id).orElseThrow(()-> new IllegalArgumentException("Not found"));
        pr.setName(n); pr.setPrice(p); return repo.save(pr);
    }
    public void delete(String id) {
        if (!repo.existsById(id)) throw new IllegalArgumentException("Not found");
        repo.deleteById(id);
    }
    public List<Product> search(String q) { return repo.findByNameContainingIgnoreCase(q); }
}
