@Entity public class Holding {
    @Id @GeneratedValue(strategy=GenerationType.UUID) private String id;
    @Column(nullable=false) private String userId;
    @Column(nullable=false) private String symbol;
    @Column(nullable=false) private int qty;
    @Column(nullable=false) private double avgBuyPrice;
    protected Holding() {}
    public Holding(String uid, String sym, int qty, double price) { userId=uid; symbol=sym; this.qty=qty; avgBuyPrice=price; }
    public String getId()       { return id; } public String getUserId()   { return userId; }
    public String getSymbol()   { return symbol; } public int    getQty()      { return qty; }
    public double getAvgBuyPrice(){ return avgBuyPrice; }
}
public interface HoldingRepository extends JpaRepository<Holding,String> {
    List<Holding> findByUserId(String uid);
    Optional<Holding> findByUserIdAndSymbol(String uid, String sym);
    @Query("SELECT SUM(h.qty) FROM Holding h WHERE h.userId=:uid AND h.symbol=:sym")
    Integer sumQtyByUserIdAndSymbol(@Param("uid") String uid, @Param("sym") String sym);
}
@Service @Transactional
public class PortfolioService {
    private final HoldingRepository repo;
    PortfolioService(HoldingRepository r) { repo=r; }
    public Holding addHolding(String uid, String sym, int qty, double price) {
        return repo.save(new Holding(uid, sym, qty, price));
    }
    public List<Holding> getPortfolio(String uid) { return repo.findByUserId(uid); }
    public double getTotalValue(String uid, java.util.Map<String,Double> prices) {
        return repo.findByUserId(uid).stream()
            .mapToDouble(h -> h.getQty() * prices.getOrDefault(h.getSymbol(), h.getAvgBuyPrice()))
            .sum();
    }
    public void removeHolding(String id) {
        if (!repo.existsById(id)) throw new IllegalArgumentException("Not found: "+id);
        repo.deleteById(id);
    }
}
@DataJpaTest @Import(PortfolioService.class)
class PortfolioServiceTest {
    @Autowired HoldingRepository repo; @Autowired PortfolioService service;
    @Test void addHolding_assignsId() { assertNotNull(service.addHolding("U01","TCS",10,2760).getId()); }
    @Test void getPortfolio_returnsOnlyUsersHoldings() {
        service.addHolding("U01","TCS",10,2760); service.addHolding("U02","INFY",5,1560);
        assertEquals(1, service.getPortfolio("U01").size());
    }
    @Test void getTotalValue_withCurrentPrices() {
        service.addHolding("U01","TCS",10,2760);
        double val = service.getTotalValue("U01", java.util.Map.of("TCS",3890.0));
        assertEquals(38900, val, 0.01);
    }
    @Test void removeHolding_removesFromDB() {
        Holding h = service.addHolding("U01","TCS",10,2760);
        service.removeHolding(h.getId());
        assertEquals(0, service.getPortfolio("U01").size());
    }
    @Test void sumQtyBySymbol_aggregates() {
        service.addHolding("U01","TCS",10,2760); service.addHolding("U01","TCS",5,2800);
        assertEquals(15, repo.sumQtyByUserIdAndSymbol("U01","TCS"));
    }
}
